import{_ as o,o as l,c as a,a2 as i}from"./chunks/framework.CW5cCyjm.js";const h=JSON.parse('{"title":"模块菜单初始化规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/backend/11-module-menu.md","filePath":"mango-pmo/rules/backend/11-module-menu.md"}'),d={name:"mango-pmo/rules/backend/11-module-menu.md"};function c(r,e,t,n,s,u){return l(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="模块菜单初始化规范" tabindex="-1">模块菜单初始化规范 <a class="header-anchor" href="#模块菜单初始化规范" aria-label="Permalink to &quot;模块菜单初始化规范&quot;">​</a></h1><h2 id="_1-归口" tabindex="-1">1. 归口 <a class="header-anchor" href="#_1-归口" aria-label="Permalink to &quot;1. 归口&quot;">​</a></h2><ul><li>功能模块自带的菜单、页面路由和按钮权限，归属功能模块自身。</li><li>授权模块只维护授权基础资产、菜单包、角色和资源清单消费能力。</li><li>功能模块禁止为自身菜单或按钮权限新增 <code>mango-authorization</code> migration。</li></ul><h2 id="_2-初始化方式" tabindex="-1">2. 初始化方式 <a class="header-anchor" href="#_2-初始化方式" aria-label="Permalink to &quot;2. 初始化方式&quot;">​</a></h2><ul><li>功能模块 <code>starter</code> 如需发布菜单，必须在 jar 内提供 Resource Registry 声明文件：<code>META-INF/mango/resources/{module}-common-menu.{json,yml,yaml}</code>。</li><li>菜单资源类型固定为 <code>AUTH_MENU</code>，由 <code>mango-authorization</code> 提供 <code>ResourceHandler</code> 消费。</li><li>一个模块的菜单优先声明为一个 <code>AUTH_MENU</code> 资源，<code>menus</code> 字段保存菜单树；菜单量大时优先使用 JSON，避免低信息密度配置。</li><li>菜单资源以 <code>appCode + moduleCode + menuCode</code> 作为菜单幂等键。</li><li>菜单资源可以引用已存在的 <code>packageCodes</code> 和 <code>roleCodes</code>，用于把菜单加入套餐或默认授权给角色。</li><li>菜单资源不得创建菜单包、角色、主体或账号。</li><li>菜单 <code>parentCode</code> 必须能解析到同一应用下已存在或本次声明的父菜单；父级缺失必须失败，禁止静默挂到一级菜单。</li><li>旧 <code>META-INF/mango/resource-manifest.json</code> 和 <code>META-INF/mango/resource-manifests/*.json</code> 只作为存量迁移对象，不得作为新增菜单标准。</li></ul><h2 id="_3-编码规则" tabindex="-1">3. 编码规则 <a class="header-anchor" href="#_3-编码规则" aria-label="Permalink to &quot;3. 编码规则&quot;">​</a></h2><ul><li>模块必须在 <code>META-INF/mango/module.properties</code> 中声明稳定 <code>module-name</code>、<code>module-path</code> 和模块编号。</li><li>模块编号为 3 位数字，全平台唯一，并登记在公开模块清单中。</li><li>菜单编码必须长期稳定，优先使用业务语义编码；需要数字排序编号时使用 <code>模块编号(3位) + 子模块编号(3位) + 菜单编号(4位)</code>。</li><li>模块根菜单或一级能力目录的数字编号以模块编号开头。</li><li>子模块编号为 3 位，同一模块内唯一。</li><li>子模块内菜单编号为 4 位，同一子模块内唯一。</li><li>权限码不得和同一模块内菜单 <code>menuCode</code> 复用；按钮菜单需要复用接口权限时，必须显式提供独立 <code>menuCode</code> 和真实 <code>permissionCode</code>。</li><li><code>permissionItems.packageCodes</code>、<code>permissionItems.roleCodes</code> 未配置时继承所属菜单；显式空数组表示不加入套餐或不授权角色。</li></ul><h2 id="_4-前端一致性" tabindex="-1">4. 前端一致性 <a class="header-anchor" href="#_4-前端一致性" aria-label="Permalink to &quot;4. 前端一致性&quot;">​</a></h2><ul><li>菜单 <code>path</code> 必须匹配前端路由。</li><li>菜单 <code>component</code> 必须匹配前端页面注册键。</li><li>按钮权限码必须匹配前端真实权限点和后端接口访问策略。</li></ul><h2 id="_5-部署与同步" tabindex="-1">5. 部署与同步 <a class="header-anchor" href="#_5-部署与同步" aria-label="Permalink to &quot;5. 部署与同步&quot;">​</a></h2><ul><li>单体部署入口必须装配本地 Resource Registry runtime 和资源同步入口。</li><li>微服务或能力 app 只上报本服务资源声明时，必须通过远程 Resource Registry starter 上报到资源中心。</li><li>Resource 服务接收远程声明后，必须能根据资源 <code>targetModule</code> 找到本地 handler 或远程 target dispatcher。</li><li>同一批资源存在多个 <code>targetModule</code> 时必须按目标模块分桶同步。</li><li>缺失资源禁用必须按来源应用、来源服务和模块边界计算，不得跨服务误禁用其它服务的资源。</li></ul><h2 id="_6-禁止事项" tabindex="-1">6. 禁止事项 <a class="header-anchor" href="#_6-禁止事项" aria-label="Permalink to &quot;6. 禁止事项&quot;">​</a></h2><ul><li>禁止把功能模块菜单初始化 SQL 写入非归属模块。</li><li>禁止用 Flyway SQL 维护菜单、按钮权限、菜单运行时配置、套餐授权和默认角色授权数据。</li><li>禁止用 README、设计文档或 evidence 代替资源清单。</li><li>禁止让资源清单覆盖或删除清单中不存在的历史授权资产。</li></ul><h2 id="_7-验收要求" tabindex="-1">7. 验收要求 <a class="header-anchor" href="#_7-验收要求" aria-label="Permalink to &quot;7. 验收要求&quot;">​</a></h2><ul><li>菜单迁移必须按模块逐个处理。</li><li>每迁移一个模块，必须完成菜单树截图、菜单入口路径、关键页面打开结果、console/network 检查和用户人工确认。</li><li>未完成人工确认前，不得继续迁移下一个模块菜单。</li><li>发布前必须在干净库验证 Resource Registry 同步、<code>AUTH_MENU</code> handler 消费、菜单无孤儿、套餐绑定、角色授权、<code>/auth/info</code> 权限和当前用户菜单树。</li></ul>',15)])])}const _=o(d,[["render",c]]);export{h as __pageData,_ as default};
